module alu_32bit (rst_alu_out, clk, reset, en, data_a, data_b, alu_ctrl);
   input clk, reset, en;
   input [31:0] data_a, data_b;
   input [2:0] alu_ctrl;
   output [31:0] rst_alu_out;

   reg [31:0] rst_alu_out;

   always @(posedge clk or posedge reset) begin
      if (reset)
         rst_alu_out <= 32'b0;
      else if (en) begin
         case (alu_ctrl)
            3'b000: rst_alu_out <= data_a + data_b;  // Addition
            3'b001: rst_alu_out <= data_a - data_b;  // Subtraction
            3'b010: rst_alu_out <= data_a & data_b;  // Bitwise AND
            3'b011: rst_alu_out <= data_a | data_b;  // Bitwise OR
            3'b100: rst_alu_out <= data_a ^ data_b;  // Bitwise XOR
            default: rst_alu_out <= 32'b0;
         endcase
      end
   end

endmodule
